/**
 * Return first day of week for locale identifier.
 * Based on:
 * - [https://github.com/gamtiq/weekstart/blob/master/src/api.js](https://github.com/gamtiq/weekstart/blob/master/src/api.js)
 * - It got modified to only rely on the region/country and ignore the language.
 * @return {number}
 *      Code of first day of week for the given locale identifier:
 *      0 - Sunday, 1 - Monday, 2 - Tuesday, 3 - Wednesday, 4 - Thursday, 5 - Friday, 6 - Saturday.
 */
export declare function getWeekStartByLocale(locale: string): number;
